// Parse Gemini response into individual job items
const response = $input.first().json;
let text = '';

try {
  text = response.candidates[0].content.parts[0].text;
} catch (e) {
  return [{ json: { error: 'No Gemini response', raw: JSON.stringify(response).substring(0, 500) } }];
}

text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let jobs = [];
try {
  jobs = JSON.parse(text);
} catch (e) {
  const match = text.match(/\[[\s\S]*\]/);
  if (match) {
    try { jobs = JSON.parse(match[0]); } catch (e2) { jobs = []; }
  }
}

if (!Array.isArray(jobs) || jobs.length === 0) {
  return [{ json: { status: 'no_jobs_found', scraped_at: new Date().toISOString() } }];
}

// Deduplicate
const seen = new Set();
const unique = jobs.filter(job => {
  const key = `${(job.title || '').toLowerCase()}_${(job.company || '').toLowerCase()}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return unique.map(job => ({ json: job }));

