const response = $input.first().json;
let text = '';
try {
  text = response.candidates[0].content.parts[0].text;
} catch (e) {
  return [{ json: { error: 'Gemini tailor failed' } }];
}

text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let tailored;
try {
  tailored = JSON.parse(text);
} catch (e) {
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try { tailored = JSON.parse(match[0]); } catch (e2) {
      return [{ json: { error: 'JSON parse failed', raw: text.substring(0, 300) } }];
    }
  }
